import type { ModelMessage } from "ai";
import { describe, expect, it } from "vitest";
import type {
  ActualTokenUsage,
  ActualTokenUsageInput,
  CheckpointLine,
  CheckpointMessage,
  CompactionConfig,
  CompactionResult,
  CompactionSegment,
  CompactionSummary,
  ContextUsage,
  ContinuationVariant,
  Message,
  MessageLine,
  PreparedCompaction,
  PreparedCompactionSegment,
  PreparedCompactionV2,
  PruningConfig,
  SessionFileLine,
  SessionHeaderLine,
  SessionMetadata,
  StructuredState,
  TodoItem,
} from "./compaction-types";

// ============================================================================
// Message Interface Tests
// ============================================================================
describe("Message", () => {
  it("accepts valid Message with all required fields", () => {
    const modelMessage: ModelMessage = {
      role: "user",
      content: "Hello, world!",
    };
    const message: Message = {
      createdAt: new Date("2024-01-01T00:00:00Z"),
      id: "msg-123",
      modelMessage,
    };

    expect(message.createdAt).toBeInstanceOf(Date);
    expect(message.id).toBe("msg-123");
    expect(message.modelMessage).toEqual(modelMessage);
  });

  it("accepts Message with optional originalContent field", () => {
    const modelMessage: ModelMessage = {
      role: "assistant",
      content: "Summarized content",
    };
    const message: Message = {
      createdAt: new Date(),
      id: "msg-456",
      modelMessage,
      originalContent: "Original long content before compaction",
    };

    expect(message.originalContent).toBe("Original long content before compaction");
  });

  it("originalContent is optional and can be undefined", () => {
    const modelMessage: ModelMessage = { role: "user", content: "test" };
    const message: Message = {
      createdAt: new Date(),
      id: "msg-789",
      modelMessage,
    };

    expect(message.originalContent).toBeUndefined();
  });

  it("all fields have correct types", () => {
    const modelMessage: ModelMessage = { role: "user", content: "test" };
    const message: Message = {
      createdAt: new Date(),
      id: "test-id",
      modelMessage,
    };

    expect(typeof message.id).toBe("string");
    expect(message.createdAt instanceof Date).toBe(true);
    expect(message.modelMessage).toBeDefined();
  });
});

// ============================================================================
// CheckpointMessage Interface Tests
// ============================================================================
describe("CheckpointMessage", () => {
  it("accepts valid CheckpointMessage with all required fields", () => {
    const modelMessage: ModelMessage = {
      role: "assistant",
      content: "Summary of conversation",
    };
    const checkpoint: CheckpointMessage = {
      createdAt: Date.now(),
      id: "ckpt-abc123",
      isSummary: true,
      message: modelMessage,
    };

    expect(typeof checkpoint.createdAt).toBe("number");
    expect(checkpoint.id).toBe("ckpt-abc123");
    expect(checkpoint.isSummary).toBe(true);
    expect(checkpoint.message).toEqual(modelMessage);
  });

  it("accepts CheckpointMessage with optional originalContent", () => {
    const modelMessage: ModelMessage = {
      role: "assistant",
      content: "Rewritten summary",
    };
    const checkpoint: CheckpointMessage = {
      createdAt: Date.now(),
      id: "ckpt-def456",
      isSummary: false,
      message: modelMessage,
      originalContent: "Original content before rewrite",
    };

    expect(checkpoint.originalContent).toBe("Original content before rewrite");
  });

  it("originalContent is optional and defaults to undefined", () => {
    const checkpoint: CheckpointMessage = {
      createdAt: Date.now(),
      id: "ckpt-ghi789",
      isSummary: true,
      message: { role: "assistant", content: "test" },
    };

    expect(checkpoint.originalContent).toBeUndefined();
  });

  it("isSummary can be true or false", () => {
    const summaryCheckpoint: CheckpointMessage = {
      createdAt: Date.now(),
      id: "ckpt-1",
      isSummary: true,
      message: { role: "assistant", content: "summary" },
    };
