// CompactionConfig Interface Tests
// ============================================================================
describe("CompactionConfig", () => {
  it("accepts empty config (all fields optional)", () => {
    const config: CompactionConfig = {};
    expect(config).toBeDefined();
  });

  it("accepts config with all fields specified", () => {
    const config: CompactionConfig = {
      contextLimit: 128000,
      enabled: true,
      keepRecentTokens: 3000,
      maxTokens: 10000,
      reserveTokens: 4000,
      speculativeStartRatio: 0.75,
      summarizeFn: async (messages: ModelMessage[], previousSummary?: string) => {
        return `Summary of ${messages.length} messages. Previous: ${previousSummary ?? "none"}`;
      },
      thresholdRatio: 0.7,
    };

    expect(config.contextLimit).toBe(128000);
    expect(config.enabled).toBe(true);
    expect(config.keepRecentTokens).toBe(3000);
    expect(config.maxTokens).toBe(10000);
    expect(config.reserveTokens).toBe(4000);
    expect(config.speculativeStartRatio).toBe(0.75);
    expect(config.thresholdRatio).toBe(0.7);
    expect(config.summarizeFn).toBeDefined();
  });

  // JSDoc default value tests
  it("enabled defaults to false (JSDoc @default false)", () => {
    const config: CompactionConfig = {};
    expect(config.enabled).toBeUndefined(); // Not set = undefined
  });

  it("keepRecentTokens has JSDoc default of 2000", () => {
    const config: CompactionConfig = {};
    // When not specified, keepRecentTokens is undefined
    expect(config.keepRecentTokens).toBeUndefined();
    // Runtime code should use 2000 as default
  });

  it("maxTokens has JSDoc default of 8000", () => {
    const config: CompactionConfig = {};
    expect(config.maxTokens).toBeUndefined();
    // Runtime code should use 8000 as default
  });

  it("reserveTokens has JSDoc default of 2000", () => {
    const config: CompactionConfig = {};
    expect(config.reserveTokens).toBeUndefined();
    // Runtime code should use 2000 as default
  });

  it("thresholdRatio has JSDoc default of 0.5", () => {
    const config: CompactionConfig = {};
    expect(config.thresholdRatio).toBeUndefined();
    // Runtime code should use 0.5 as default
  });

  it("contextLimit can be 0 for unlimited context", () => {
    const config: CompactionConfig = {
      contextLimit: 0,
    };
    expect(config.contextLimit).toBe(0);
  });

  it("speculativeStartRatio valid range is 0.15 to 0.95", () => {
    const configMin: CompactionConfig = {
      speculativeStartRatio: 0.15,
    };
    const configMax: CompactionConfig = {
      speculativeStartRatio: 0.95,
    };

    expect(configMin.speculativeStartRatio).toBe(0.15);
    expect(configMax.speculativeStartRatio).toBe(0.95);
  });

  it("summarizeFn is an async function returning string", async () => {
    const config: CompactionConfig = {
      summarizeFn: async (messages) => {
        return `Summarized ${messages.length} messages`;
      },
    };

    if (config.summarizeFn) {
      const result = await config.summarizeFn([
        { role: "user", content: "Hello" },
        { role: "assistant", content: "Hi there!" },
      ]);
      expect(result).toBe("Summarized 2 messages");
    }
  });

  it("summarizeFn accepts optional previousSummary parameter", async () => {
    const config: CompactionConfig = {
      summarizeFn: async (messages, previousSummary) => {
        return previousSummary
          ? `${previousSummary} + ${messages.length} more`
          : `New summary of ${messages.length} messages`;
      },
    };

    if (config.summarizeFn) {
      const messages: ModelMessage[] = [{ role: "user", content: "More" }];
      const resultWithPrevious = await config.summarizeFn(messages, "Previous summary");
      expect(resultWithPrevious).toBe("Previous summary + 1 more");
    }
  });
});

