describe("ContextUsage", () => {
  it("accepts valid ContextUsage with all required fields", () => {
    const usage: ContextUsage = {
      limit: 128000,
      percentage: 75.5,
      remaining: 31200,
      source: "actual",
      used: 96800,
    };

    expect(usage.limit).toBe(128000);
    expect(usage.percentage).toBe(75.5);
    expect(usage.remaining).toBe(31200);
    expect(usage.source).toBe("actual");
    expect(usage.used).toBe(96800);
  });

  it("percentage is between 0 and 100", () => {
    const lowUsage: ContextUsage = {
      limit: 100000,
      percentage: 10,
      remaining: 90000,
      source: "estimated",
      used: 10000,
    };
    const highUsage: ContextUsage = {
      limit: 100000,
      percentage: 95,
      remaining: 5000,
      source: "actual",
      used: 95000,
    };

    expect(lowUsage.percentage).toBeGreaterThanOrEqual(0);
    expect(lowUsage.percentage).toBeLessThanOrEqual(100);
    expect(highUsage.percentage).toBeGreaterThanOrEqual(0);
    expect(highUsage.percentage).toBeLessThanOrEqual(100);
  });

  it("source can be 'actual' or 'estimated'", () => {
    const actual: ContextUsage = {
      limit: 100000,
      percentage: 50,
      remaining: 50000,
      source: "actual",
      used: 50000,
    };
    const estimated: ContextUsage = {
      limit: 100000,
      percentage: 50,
      remaining: 50000,
      source: "estimated",
      used: 50000,
    };

    expect(actual.source).toBe("actual");
    expect(estimated.source).toBe("estimated");
  });

  it("used + remaining equals limit", () => {
    const usage: ContextUsage = {
      limit: 100000,
      percentage: 60,
      remaining: 40000,
      source: "actual",
      used: 60000,
    };

    expect(usage.used + usage.remaining).toBe(usage.limit);
  });
});

