  ): PreparedCompactionSegment => ({
    createdAt: new Date(),
    endMessageId: messageIds[messageIds.length - 1] || "",
    estimatedTokens: 100,
    id,
    messageCount: messageIds.length,
    messageIds,
    messages: messageIds.map((msgId) => ({
      createdAt: new Date(),
      id: msgId,
      modelMessage: { role: "user" as const, content: `Message ${msgId}` },
    })),
    startMessageId: messageIds[0] || "",
    summary: null,
  });

  it("accepts valid PreparedCompaction with all required fields", () => {
    const prepared: PreparedCompaction = {
      actualUsage: null,
      baseMessageIds: ["m1", "m2"],
      baseRevision: 1,
      baseSegmentIds: ["seg1"],
      compactionMaxTokensAtCreation: 10000,
      contextLimitAtCreation: 128000,
      didChange: false,
      keepRecentTokensAtCreation: 2000,
      pendingCompaction: false,
      phase: "intermediate-step",
      rejected: false,
      segments: [createTestSegment("seg1", ["m1", "m2"])],
      tokenDelta: 0,
    };

    expect(prepared.baseMessageIds).toEqual(["m1", "m2"]);
    expect(prepared.baseRevision).toBe(1);
    expect(prepared.segments.length).toBe(1);
    expect(prepared.phase).toBe("intermediate-step");
  });

  it("accepts actualUsage with token data", () => {
    const actualUsage: ActualTokenUsage = {
      completionTokens: 500,
      promptTokens: 2000,
      totalTokens: 2500,
