  });

  it("phase can be 'new-turn'", () => {
    const prepared: PreparedCompaction = {
      actualUsage: null,
      baseMessageIds: [],
      baseRevision: 1,
      baseSegmentIds: [],
      compactionMaxTokensAtCreation: 8000,
      contextLimitAtCreation: 128000,
      didChange: true,
