      segments: [],
      tokenDelta: -100,
    };

    expect(prepared.phase).toBe("new-turn");
  });

  it("didChange can be true or false", () => {
    const changed: PreparedCompaction = {
      actualUsage: null,
      baseMessageIds: [],
      baseRevision: 1,
      baseSegmentIds: [],
      compactionMaxTokensAtCreation: 8000,
      contextLimitAtCreation: 128000,
      didChange: true,
      keepRecentTokensAtCreation: 2000,
      pendingCompaction: false,
      phase: "new-turn",
      rejected: false,
      segments: [],
      tokenDelta: -500,
    };
    const unchanged: PreparedCompaction = {
      actualUsage: null,
      baseMessageIds: [],
      baseRevision: 1,
      baseSegmentIds: [],
      compactionMaxTokensAtCreation: 8000,
      contextLimitAtCreation: 128000,
      didChange: false,
      keepRecentTokensAtCreation: 2000,
      pendingCompaction: false,
      phase: "intermediate-step",
      rejected: false,
      segments: [],
      tokenDelta: 0,
